A client says: "When I submit the login form, the page flashes white and then I am back at the login form with empty fields." What is the bug?

```jsx
function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  function handleSubmit() {
    fetch('/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password }),
    })
      .then(res => res.json())
      .then(data => {
        localStorage.setItem('token', data.token);
        window.location.href = '/dashboard';
      });
  }

  return (
    <form onSubmit={handleSubmit}>
      <input value={email} onChange={e => setEmail(e.target.value)} />
      <input
        type="password"
        value={password}
        onChange={e => setPassword(e.target.value)}
      />
      <button type="submit">Log In</button>
    </form>
  );
}
```

You are reviewing AI-generated code for a user settings form. The client says: "When I change the email field, my display name disappears." What would you tell the AI to fix?

```jsx
function SettingsForm() {
  const [settings, setSettings] = useState({
    displayName: 'Alice',
    email: 'alice@example.com',
    bio: 'Hello world',
  });

  return (
    <form>
      <input
        value={settings.displayName}
        onChange={(e) => setSettings({ displayName: e.target.value })}
      />
      <input
        value={settings.email}
        onChange={(e) => setSettings({ email: e.target.value })}
      />
      <textarea
        value={settings.bio}
        onChange={(e) => setSettings({ bio: e.target.value })}
      />
    </form>
  );
}
```
